import { ref } from 'vue'

export type AppLocale = 'en' | 'zh-CN'

const storageKey = 'md-html-reader.locale'

function readInitialLocale(): AppLocale {
  try {
    return window.localStorage.getItem(storageKey) === 'zh-CN' ? 'zh-CN' : 'en'
  } catch {
    return 'en'
  }
}

export const locale = ref<AppLocale>(readInitialLocale())

export function setLocale(nextLocale: AppLocale) {
  locale.value = nextLocale
  try {
    window.localStorage.setItem(storageKey, nextLocale)
  } catch {
    // The selected language remains available for this session.
  }
}

